-- 预置概览 Widget（11个固定卡片，用户只需修改 SQL）
-- 5个数字指标
(1, '活跃用户数', 'metric', NULL, 'SELECT COUNT(*) AS value FROM owl_users WHERE status = ''active''', NULL, 'value', '人', 1, true, now(), now()),
(2, '总用户数', 'metric', NULL, 'SELECT COUNT(*) AS value FROM owl_users', NULL, 'value', '人', 2, true, now(), now()),
(3, '近7天登录', 'metric', NULL, 'SELECT COUNT(*) AS value FROM owl_users WHERE last_login_at >= NOW() - INTERVAL ''7 days''', NULL, 'value', '人', 3, true, now(), now()),
(4, '系统运行天数', 'metric', NULL, 'SELECT EXTRACT(DAY FROM NOW() - MIN(created_at))::int AS value FROM owl_users', NULL, 'value', '天', 4, true, now(), now()),
(5, '文件总数', 'metric', NULL, 'SELECT COUNT(*) AS value FROM owl_files', NULL, 'value', '个', 5, true, now(), now()),
-- 6个图表
(6, '最近登录趋势', 'chart', 'area', 'SELECT TO_CHAR(DATE_TRUNC(''day'', last_login_at), ''MM-DD'') AS date, COUNT(*) AS "登录数" FROM owl_users WHERE last_login_at >= NOW() - INTERVAL ''7 days'' GROUP BY DATE_TRUNC(''day'', last_login_at) ORDER BY DATE_TRUNC(''day'', last_login_at)', 'date', '登录数', NULL, 6, true, now(), now()),
(7, '系统概览', 'chart', 'pie', 'SELECT ''活跃用户'' AS name, COUNT(*) AS value FROM owl_users WHERE status = ''active'' UNION ALL SELECT ''角色'' AS name, COUNT(*) AS value FROM owl_roles UNION ALL SELECT ''权限'' AS name, COUNT(*) AS value FROM owl_permissions UNION ALL SELECT ''离线用户'' AS name, COUNT(*) AS value FROM owl_users WHERE status != ''active''', 'name', 'value', NULL, 7, true, now(), now()),
(8, '存储概览', 'chart', 'bar', 'SELECT CASE WHEN mime_type LIKE ''image/%'' OR mime_type LIKE ''video/%'' OR mime_type LIKE ''audio/%'' THEN ''媒体'' WHEN mime_type LIKE ''%pdf%'' OR mime_type LIKE ''%word%'' OR mime_type LIKE ''%text%'' THEN ''文档'' ELSE ''其他'' END AS name, ROUND(SUM(size) / 1073741824.0, 2) AS value FROM owl_files GROUP BY 1', 'name', 'value', 'GB', 8, true, now(), now()),
(9, '操作统计', 'chart', 'bar', 'SELECT action AS name, COUNT(*) AS value FROM owl_operation_logs GROUP BY action ORDER BY value DESC LIMIT 6', 'name', 'value', '次', 9, true, now(), now()),
(10, '在线用户趋势', 'chart', 'area', 'SELECT TO_CHAR(DATE_TRUNC(''hour'', last_login_at), ''HH24:MI'') AS time, COUNT(*) AS "在线用户" FROM owl_users WHERE last_login_at >= NOW() - INTERVAL ''12 hours'' GROUP BY DATE_TRUNC(''hour'', last_login_at) ORDER BY DATE_TRUNC(''hour'', last_login_at)', 'time', '在线用户', NULL, 10, true, now(), now()),
(11, '访问趋势', 'chart', 'area', 'SELECT TO_CHAR(DATE_TRUNC(''day'', last_login_at), ''MM-DD'') AS date, COUNT(*) AS visits FROM owl_users WHERE last_login_at >= NOW() - INTERVAL ''7 days'' GROUP BY DATE_TRUNC(''day'', last_login_at) ORDER BY DATE_TRUNC(''day'', last_login_at)', 'date', 'visits', NULL, 11, true, now(), now())
